{
  "file": "backend/prompts/system_prompt.py",
  "summary": "This file contains a system prompt for generating user stories, development tasks, and unit test tasks based on a Solution Design Document (SDD) and relevant context from the codebase. The prompt outlines strict rules for output formatting and content generation to ensure consistency and adherence to technical requirements.",
  "rules": [
    {
      "name": "Logical Role Description",
      "description": "Describe affected code by logical role only, avoiding specific file names or class names.",
      "conditions": ["When describing components in the SDD text"],
      "actions": ["Use generic descriptions like 'customer validation service'"]
    },
    {
      "name": "Layer Determination",
      "description": "Determine which layers are affected (frontend/backend/middleware/database) directly from the SDD and context.",
      "conditions": ["When identifying impacted components"],
      "actions": ["Specify each layer explicitly or mark as 'N/A' with justification"]
    },
    {
      "name": "Component Grounding",
      "description": "Ensure `affected_components` values are grounded in retrieved codebase context.",
      "conditions": ["When populating the affected components section"],
      "actions": ["Reference specific chunks from the codebase when available, avoid inventing behavior"]
    },
    {
      "name": "API Contract Specification",
      "description": "Populate `api_contract` with endpoint details and status codes based on retrieved context.",
      "conditions": ["When describing API changes"],
      "actions": ["Use Controller-layer chunks for request/response shapes; set to 'N/A' if no surface change"]
    },
    {
      "name": "Database Reference",
      "description": "Reference JPA Entity context for database tasks, describe implied changes explicitly.",
      "conditions": ["When describing database-related tasks"],
      "actions": ["Use entity context when available, describe changes otherwise"]
    },
    {
      "name": "Technical Approach Guidance",
      "description": "Provide technical guidance on what needs to change and why without step-by-step instructions or design patterns.",
      "conditions": ["When writing the technical approach section"],
      "actions": ["Describe WHAT needs to change and WHY, grounded in context"]
    },
    {
      "name": "Task-Test Pairing",
      "description": "Ensure each dev task has a corresponding unit test task with matching titles.",
      "conditions": ["When creating unit tests"],
      "actions": ["Create a 1:1 mapping between dev tasks and unit tests, referencing the dev task title"]
    },
    {
      "name": "Output Format",
      "description": "Respond only with valid JSON adhering to the provided schema without additional commentary.",
      "conditions": ["When generating output"],
      "actions": ["Ensure response is parseable as-is using `json.loads`"]
    }
  ],
  "dependencies": [
    "Solution Design Document (SDD)",
    "Retrieved User Manual context",
    "Retrieved Codebase context",
    "Retrieved JPA Entity context"
  ]
}
